#nullable enable // autogenerated

using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Projectiles;
using MVZ2.Vanilla.Properties;
using MVZ2Logic;
using MVZ2Logic.Inputs;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaContraptionNames.MegaSnipenser)]
    public class MegaSnipenser : AIEntityBehaviour
    {
        public MegaSnipenser(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new FloatModifier(VanillaEntityProps.ATTACK_SPEED, NumberOperator.AddMultiple, PROP_ATTACK_SPEED_ADDITION));
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            var shootTimer = new FrameTimer(10);
            SetShootTimer(entity, shootTimer);
        }

        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);

            if (Global.Input.TryGetPointerScreenPosition(out var screenPosition))
            {
                var levelPosition = entity.Level.ScreenToLawnPositionByY(screenPosition, entity.Position.y);
                var distanceVector = new Vector2(levelPosition.x - entity.Position.x, levelPosition.z - entity.Position.z);
                var angle = Mathf.Repeat(Vector2.SignedAngle(distanceVector, Vector2.right), 360f);
                SetDirection(entity, angle);
            }


            var shootTimer = GetShootTimer(entity);
            if (shootTimer.RunToExpiredAndNotNull(entity.GetAttackSpeed()))
            {
                if (Global.Input.IsPointerHolding(PointerTypes.MOUSE, 0) || Global.Input.IsPointerHolding(PointerTypes.TOUCH, 0))
                {
                    Shoot(entity);
                    shootTimer.Reset();
                }
            }


            var headOffset = GetHeadOffset(entity);
            headOffset = Ticks.SmoothDamp(headOffset, Vector2.zero, 0.5f);
            SetHeadOffset(entity, headOffset);
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            float headSpritePercentage = 0;
            var headOffset = GetHeadOffset(entity);
            var direction = GetDirection(entity);
            var spriteDirection = direction;
            if (entity.IsFacingLeft())
            {
                spriteDirection = 180f - direction - SPRITE_ANGLE_OFFSET;
            }
            else
            {
                spriteDirection = direction - SPRITE_ANGLE_OFFSET;
            }
            headSpritePercentage = Mathf.Repeat(spriteDirection, 360) / 360f;
            entity.SetAnimationFloat("HeadOffsetX", headOffset.x);
            entity.SetAnimationFloat("HeadOffsetY", headOffset.y);
            entity.SetAnimationFloat("HeadSprite", headSpritePercentage);

            entity.SetProperty(PROP_ATTACK_SPEED_ADDITION, GetRapidLevel(entity) * ATTACK_SPEED_PER_RAPID_LEVEL);
        }
        public void Shoot(Entity entity)
        {
            var direction = GetDirection(entity);
            var directionVector2 = Vector2.right.RotateClockwise(direction);
            var headOffset = -directionVector2;
            SetHeadOffset(entity, headOffset);

            var shotOffset = entity.GetShotOffset();
            var shotOffset2D = new Vector2(shotOffset.x, shotOffset.z);
            shotOffset2D = shotOffset2D.RotateClockwise(direction);
            shotOffset = new Vector3(shotOffset2D.x, shotOffset.y, shotOffset2D.y);
            var position = entity.Position + shotOffset;

            var velocity = entity.GetShotVelocity();
            var speed = velocity.magnitude;

            var spawnParam = entity.GetSpawnParams();
            spawnParam.SetProperty(EngineEntityProps.SIZE, Vector3.one * 32f);

            var spreadCount = GetSpreadLevel(entity) + 1;
            var startAngleOffset = -ANGLE_PER_SPREAD * ((spreadCount - 1) / 2f);
            for (int i = 0; i < spreadCount; i++)
            {
                var angleOffset = i * ANGLE_PER_SPREAD + startAngleOffset;
                var velDirection = directionVector2.RotateClockwise(angleOffset);
                var vel = speed * new Vector3(velDirection.x, 0, velDirection.y);

                var param = entity.GetShootParams();
                param.position = position;
                param.velocity = vel;
                param.spawnParam = spawnParam;
                entity.ShootProjectile(param);
            }
        }
        public static bool CanUpgradeRapid(Entity entity)
        {
            return GetRapidLevel(entity) < MAX_RAPID_LEVEL;
        }
        public static void UpgradeRapid(Entity entity)
        {
            SetRapidLevel(entity, GetRapidLevel(entity) + 1);
        }
        public static bool CanUpgradeSpread(Entity entity)
        {
            return GetSpreadLevel(entity) < MAX_SPREAD_LEVEL;
        }
        public static void UpgradeSpread(Entity entity)
        {
            SetSpreadLevel(entity, GetSpreadLevel(entity) + 1);
        }
        public static FrameTimer? GetShootTimer(Entity entity) => entity.GetBehaviourField<FrameTimer>(PROP_SHOOT_TIMER);
        public static void SetShootTimer(Entity entity, FrameTimer value) => entity.SetBehaviourField(PROP_SHOOT_TIMER, value);
        public static float GetDirection(Entity entity) => entity.GetBehaviourField<float>(PROP_DIRECTION);
        public static void SetDirection(Entity entity, float value) => entity.SetBehaviourField(PROP_DIRECTION, value);
        public static int GetRapidLevel(Entity entity) => entity.GetBehaviourField<int>(PROP_RAPID_LEVEL);
        public static void SetRapidLevel(Entity entity, int value) => entity.SetBehaviourField(PROP_RAPID_LEVEL, value);
        public static int GetSpreadLevel(Entity entity) => entity.GetBehaviourField<int>(PROP_SPREAD_LEVEL);
        public static void SetSpreadLevel(Entity entity, int value) => entity.SetBehaviourField(PROP_SPREAD_LEVEL, value);
        public static Vector2 GetHeadOffset(Entity entity) => entity.GetBehaviourField<Vector2>(PROP_HEAD_OFFSET);
        public static void SetHeadOffset(Entity entity, Vector2 value) => entity.SetBehaviourField(PROP_HEAD_OFFSET, value);
        public const float FRAME_COUNT = 24;
        public const float SPRITE_ANGLE_OFFSET = 360f / FRAME_COUNT / 2;
        public const float ATTACK_SPEED_PER_RAPID_LEVEL = 0.25f;
        public const float ANGLE_PER_SPREAD = 5;
        public const int MAX_RAPID_LEVEL = 4;
        public const int MAX_SPREAD_LEVEL = 4;
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_SHOOT_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("shoot_timer");
        public static readonly VanillaEntityPropertyMeta<float> PROP_DIRECTION = new VanillaEntityPropertyMeta<float>("direction");
        public static readonly VanillaEntityPropertyMeta<int> PROP_RAPID_LEVEL = new VanillaEntityPropertyMeta<int>("rapid_level");
        public static readonly VanillaEntityPropertyMeta<float> PROP_ATTACK_SPEED_ADDITION = new VanillaEntityPropertyMeta<float>("attack_speed_addition");
        public static readonly VanillaEntityPropertyMeta<int> PROP_SPREAD_LEVEL = new VanillaEntityPropertyMeta<int>("spread_level");
        public static readonly VanillaEntityPropertyMeta<Vector2> PROP_HEAD_OFFSET = new VanillaEntityPropertyMeta<Vector2>("head_offset");
    }
}
